#!/usr/bin/env python3
"""Generate .resx localization files for BUtil."""
import xml.etree.ElementTree as ET
import copy
import os

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
TEMPLATE = os.path.join(SCRIPT_DIR, "Resources.de.resx")

def get_header_xml():
    with open(TEMPLATE, "r", encoding="utf-8") as f:
        content = f.read()
    idx = content.index('<data name="_Technical_NsisLanguage"')
    return content[:idx]

def build_resx(translations, header):
    lines = [header.rstrip()]
    keys = sorted(translations.keys())
    for key in keys:
        val = translations[key]
        val_escaped = val.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")
        val_escaped = val_escaped.replace("&amp;gt;", "&gt;").replace("&amp;amp;", "&amp;").replace("&amp;lt;", "&lt;")
        lines.append(f'  <data name="{key}" xml:space="preserve">')
        lines.append(f'    <value>{val_escaped}</value>')
        lines.append(f'  </data>')
    lines.append('</root>')
    return "\n".join(lines)

def read_english():
    tree = ET.parse(os.path.join(SCRIPT_DIR, "Resources.resx"))
    root = tree.getroot()
    d = {}
    for data in root.findall("data"):
        name = data.get("name")
        value_el = data.find("value")
        if value_el is not None and value_el.text is not None:
            d[name] = value_el.text
        elif value_el is not None:
            d[name] = ""
    return d

